func resourceChronicleFeedCreate(d *schema.ResourceData, meta interface{}) error {
	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}

	obj := make(map[string]interface{})
	enabledProp, err := expandChronicleFeedEnabled(d.Get("enabled"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("enabled"); !tpgresource.IsEmptyValue(reflect.ValueOf(enabledProp)) && (ok || !reflect.DeepEqual(v, enabledProp)) {
		obj["enabled"] = enabledProp
	}
	detailsProp, err := expandChronicleFeedDetails(d.Get("details"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("details"); !tpgresource.IsEmptyValue(reflect.ValueOf(detailsProp)) && (ok || !reflect.DeepEqual(v, detailsProp)) {
		obj["details"] = detailsProp
	}
	displayNameProp, err := expandChronicleFeedDisplayName(d.Get("display_name"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("display_name"); !tpgresource.IsEmptyValue(reflect.ValueOf(displayNameProp)) && (ok || !reflect.DeepEqual(v, displayNameProp)) {
		obj["displayName"] = displayNameProp
	}
	failureDetailsProp, err := expandChronicleFeedFailureDetails(d.Get("failure_details"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("failure_details"); !tpgresource.IsEmptyValue(reflect.ValueOf(failureDetailsProp)) && (ok || !reflect.DeepEqual(v, failureDetailsProp)) {
		obj["failureDetails"] = failureDetailsProp
	}
	feedProp, err := expandChronicleFeedFeed(d.Get("feed"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("feed"); !tpgresource.IsEmptyValue(reflect.ValueOf(feedProp)) && (ok || !reflect.DeepEqual(v, feedProp)) {
		obj["feed"] = feedProp
	}

	url, err := tpgresource.ReplaceVars(d, config, transport_tpg.BaseUrl(Product, config)+"projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds")
	if err != nil {
		return err
	}

	log.Printf("[DEBUG] Creating new Feed: %#v", obj)
	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for Feed: %s", err)
	}
	billingProject = project

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	headers := make(http.Header)
	// Fetch service account for GOOGLE_CLOUD_STORAGE or GOOGLE_CLOUD_STORAGE_EVENT_DRIVEN
	if v, ok := d.GetOk("details.0.feed_source_type"); ok {
		sourceType := v.(string)
		if sourceType == "GOOGLE_CLOUD_STORAGE" || sourceType == "GOOGLE_CLOUD_STORAGE_EVENT_DRIVEN" {
			log.Printf("[DEBUG] Fetching service account for Chronicle feed of type %s", sourceType)

			url, err := tpgresource.ReplaceVars(d, config, "{{ChronicleBasePath}}projects/{{project}}/locations/{{location}}/instances/{{instance}}/feedServiceAccounts:fetchServiceAccountForCustomer")
			if err != nil {
				return err
			}

			res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
				Config:    config,
				Method:    "GET",
				Project:   billingProject,
				RawURL:    url,
				UserAgent: userAgent,
			})
			if err != nil {
				return fmt.Errorf("Error fetching service account for Chronicle feed: %s", err)
			}

			// The response has a `name` field formatted as `projects/.../feedServiceAccounts/{service_account_email}`
			if nameVal, ok := res["name"].(string); ok {
				parts := strings.Split(nameVal, "/")
				if len(parts) > 0 {
					saEmail := parts[len(parts)-1]

					// Make the value reach the customer's state
					if err := d.Set("feed_service_account", saEmail); err != nil {
						return fmt.Errorf("Error setting feed_service_account in state: %s", err)
					}
					log.Printf("[DEBUG] Successfully fetched and set feed_service_account: %s", saEmail)
				}
			} else {
				log.Printf("[WARN] No name returned by fetchServiceAccountForCustomer for Chronicle feed")
			}
		}
	}
	res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
		Config:    config,
		Method:    "POST",
		Project:   billingProject,
		RawURL:    url,
		UserAgent: userAgent,
		Body:      obj,
		Timeout:   d.Timeout(schema.TimeoutCreate),
		Headers:   headers,
	})
	if err != nil {
		return fmt.Errorf("Error creating Feed: %s", err)
	}
	// Set computed resource properties from create API response so that they're available on the subsequent Read
	// call.
	err = resourceChronicleFeedPostCreateSetComputedFields(d, meta, res)
	if err != nil {
		return fmt.Errorf("setting computed ID format fields: %w", err)
	}

	// Store the ID now
	id, err := tpgresource.ReplaceVars(d, config, "projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}")
	if err != nil {
		return fmt.Errorf("Error constructing id: %s", err)
	}
	d.SetId(id)

	// Generate secret for HTTPS_PUSH_AMAZON_KINESIS_FIREHOSE feed post-creation
	if v, ok := d.GetOk("details.0.feed_source_type"); ok && v.(string) == "HTTPS_PUSH_AMAZON_KINESIS_FIREHOSE" {
		log.Printf("[DEBUG] Generating secret for HTTPS_PUSH_AMAZON_KINESIS_FIREHOSE feed %q", d.Id())

		url, err := tpgresource.ReplaceVars(d, config, "{{ChronicleBasePath}}projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}:generateSecret")
		if err != nil {
			return err
		}

		res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
			Config:    config,
			Method:    "POST",
			Project:   billingProject,
			RawURL:    url,
			UserAgent: userAgent,
		})

		if err != nil {
			return fmt.Errorf("Error generating secret for Chronicle feed %q: %s", d.Id(), err)
		}

		// Store the secret returned by the API so the user can reference it (e.g. `google_chronicle_feed.example.secret`)
		if secretValue, ok := res["secret"].(string); ok {
			if err := d.Set("secret", secretValue); err != nil {
				return fmt.Errorf("Error setting secret in state for Chronicle feed %q: %s", d.Id(), err)
			}
		} else {
			log.Printf("[WARN] No secret returned by generateSecret for Chronicle feed %q", d.Id())
		}
	}

	log.Printf("[DEBUG] Finished creating Feed %q: %#v", d.Id(), res)

	identity, err := d.Identity()
	if err == nil && identity != nil {
		if locationValue, ok := d.GetOk("location"); ok && locationValue.(string) != "" {
			if err = identity.Set("location", locationValue.(string)); err != nil {
				return fmt.Errorf("Error setting location: %s", err)
			}
		}
		if instanceValue, ok := d.GetOk("instance"); ok && instanceValue.(string) != "" {
			if err = identity.Set("instance", instanceValue.(string)); err != nil {
				return fmt.Errorf("Error setting instance: %s", err)
			}
		}
		if feedValue, ok := d.GetOk("feed"); ok && feedValue.(string) != "" {
			if err = identity.Set("feed", feedValue.(string)); err != nil {
				return fmt.Errorf("Error setting feed: %s", err)
			}
		}
		if projectValue, ok := d.GetOk("project"); ok && projectValue.(string) != "" {
			if err = identity.Set("project", projectValue.(string)); err != nil {
				return fmt.Errorf("Error setting project: %s", err)
			}
		}
	} else {
		log.Printf("[DEBUG] (Create) identity not set: %s", err)
	}

	return resourceChronicleFeedRead(d, meta)
}

func resourceChronicleFeedRead(d *schema.ResourceData, meta interface{}) error {
	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}

	url, err := tpgresource.ReplaceVars(d, config, transport_tpg.BaseUrl(Product, config)+"projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}")
	if err != nil {
		return err
	}

	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for Feed: %s", err)
	}
	billingProject = project

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	headers := make(http.Header)
	res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
		Config:    config,
		Method:    "GET",
		Project:   billingProject,
		RawURL:    url,
		UserAgent: userAgent,
		Headers:   headers,
	})
	if err != nil {
		return transport_tpg.HandleNotFoundError(err, d, fmt.Sprintf("ChronicleFeed %q", d.Id()))
	}

	log.Printf("[DEBUG] Finished reading ChronicleFeed %q: %#v", d.Id(), res)

	// Explicitly set virtual fields to default values if unset
	if _, ok := d.GetOkExists("deletion_policy"); !ok {
		//prioritize config's value if present
		if config.DeletionPolicy != "" {
			if err := d.Set("deletion_policy", config.DeletionPolicy); err != nil {
				return fmt.Errorf("Error setting deletion_policy: %s", err)
			}
		} else {
			if err := d.Set("deletion_policy", "DELETE"); err != nil {
				return fmt.Errorf("Error setting deletion_policy: %s", err)
			}
		}
	}
	if err := d.Set("project", project); err != nil {
		return fmt.Errorf("Error reading Feed: %s", err)
	}

	err = ResourceChronicleFeedFlatten(d, meta, res, config, project, userAgent, billingProject, url, headers)
	if err != nil {
		return err
	}

	identity, err := d.Identity()
	if err == nil && identity != nil {
		if v, ok := identity.GetOk("location"); !ok && v == "" {
			err = identity.Set("location", d.Get("location").(string))
			if err != nil {
				return fmt.Errorf("Error setting location: %s", err)
			}
		}
		if v, ok := identity.GetOk("instance"); !ok && v == "" {
			err = identity.Set("instance", d.Get("instance").(string))
			if err != nil {
				return fmt.Errorf("Error setting instance: %s", err)
			}
		}
		if v, ok := identity.GetOk("feed"); !ok && v == "" {
			err = identity.Set("feed", d.Get("feed").(string))
			if err != nil {
				return fmt.Errorf("Error setting feed: %s", err)
			}
		}
		if v, ok := identity.GetOk("project"); !ok && v == "" {
			err = identity.Set("project", d.Get("project").(string))
			if err != nil {
				return fmt.Errorf("Error setting project: %s", err)
			}
		}
	} else {
		log.Printf("[DEBUG] (Read) identity not set: %s", err)
	}

	return nil
}

func resourceChronicleFeedUpdate(d *schema.ResourceData, meta interface{}) error {
	clientSideFields := map[string]bool{"deletion_policy": true}
	clientSideOnly := true
	for field := range ResourceChronicleFeed().Schema {
		if d.HasChange(field) && !clientSideFields[field] {
			clientSideOnly = false
			break
		}
	}
	if clientSideOnly {
		log.Print("[DEBUG] Only client-side changes detected. Cancelling update operation.")
		return resourceChronicleFeedRead(d, meta)
	}

	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}
	identity, err := d.Identity()
	if err == nil && identity != nil {
		if locationValue, ok := d.GetOk("location"); ok && locationValue.(string) != "" {
			if err = identity.Set("location", locationValue.(string)); err != nil {
				return fmt.Errorf("Error setting location: %s", err)
			}
		}
		if instanceValue, ok := d.GetOk("instance"); ok && instanceValue.(string) != "" {
			if err = identity.Set("instance", instanceValue.(string)); err != nil {
				return fmt.Errorf("Error setting instance: %s", err)
			}
		}
		if feedValue, ok := d.GetOk("feed"); ok && feedValue.(string) != "" {
			if err = identity.Set("feed", feedValue.(string)); err != nil {
				return fmt.Errorf("Error setting feed: %s", err)
			}
		}
		if projectValue, ok := d.GetOk("project"); ok && projectValue.(string) != "" {
			if err = identity.Set("project", projectValue.(string)); err != nil {
				return fmt.Errorf("Error setting project: %s", err)
			}
		}
	} else {
		log.Printf("[DEBUG] (Update) identity not set: %s", err)
	}

	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for Feed: %s", err)
	}
	billingProject = project

	obj := make(map[string]interface{})
	enabledProp, err := expandChronicleFeedEnabled(d.Get("enabled"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("enabled"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, enabledProp)) {
		obj["enabled"] = enabledProp
	}
	detailsProp, err := expandChronicleFeedDetails(d.Get("details"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("details"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, detailsProp)) {
		obj["details"] = detailsProp
	}
	displayNameProp, err := expandChronicleFeedDisplayName(d.Get("display_name"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("display_name"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, displayNameProp)) {
		obj["displayName"] = displayNameProp
	}
	failureDetailsProp, err := expandChronicleFeedFailureDetails(d.Get("failure_details"), d, config)
	if err != nil {
		return err
	} else if v, ok := d.GetOkExists("failure_details"); !tpgresource.IsEmptyValue(reflect.ValueOf(v)) && (ok || !reflect.DeepEqual(v, failureDetailsProp)) {
		obj["failureDetails"] = failureDetailsProp
	}

	obj, err = resourceChronicleFeedUpdateEncoder(d, meta, obj)
	if err != nil {
		return err
	}

	url, err := tpgresource.ReplaceVars(d, config, transport_tpg.BaseUrl(Product, config)+"projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}")
	if err != nil {
		return err
	}

	log.Printf("[DEBUG] Updating Feed %q: %#v", d.Id(), obj)
	headers := make(http.Header)
	updateMask := []string{}

	if d.HasChange("enabled") {
		updateMask = append(updateMask, "enabled")
	}

	if d.HasChange("details") {
		updateMask = append(updateMask, "details")
	}

	if d.HasChange("display_name") {
		updateMask = append(updateMask, "displayName")
	}

	if d.HasChange("failure_details") {
		updateMask = append(updateMask, "failureDetails")
	}
	// updateMask is a URL parameter but not present in the schema, so ReplaceVars
	// won't set it
	url, err = transport_tpg.AddQueryParams(url, map[string]string{"updateMask": strings.Join(updateMask, ",")})
	if err != nil {
		return err
	}

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	// if updateMask is empty we are not updating anything so skip the post
	if len(updateMask) > 0 {
		res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
			Config:    config,
			Method:    "PATCH",
			Project:   billingProject,
			RawURL:    url,
			UserAgent: userAgent,
			Body:      obj,
			Timeout:   d.Timeout(schema.TimeoutUpdate),
			Headers:   headers,
		})

		if err != nil {
			return fmt.Errorf("Error updating Feed %q: %s", d.Id(), err)
		} else {
			log.Printf("[DEBUG] Finished updating Feed %q: %#v", d.Id(), res)
		}

	}

	// Handle Enable/Disable state changes
	if d.HasChange("enabled") {
		_, newEnabled := d.GetChange("enabled")
		var stateUrl string

		if newEnabled.(bool) {
			stateUrl, err = tpgresource.ReplaceVars(d, config, "{{ChronicleBasePath}}projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}:enable")
		} else {
			stateUrl, err = tpgresource.ReplaceVars(d, config, "{{ChronicleBasePath}}projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}:disable")
		}

		if err != nil {
			return err
		}

		_, err = transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
			Config:    config,
			Method:    "POST",
			Project:   project,
			RawURL:    stateUrl,
			UserAgent: userAgent,
			Body:      nil,
			Timeout:   d.Timeout(schema.TimeoutUpdate),
		})
		if err != nil {
			return fmt.Errorf("Error changing Feed state: %s", err)
		}
	}
	return resourceChronicleFeedRead(d, meta)
}

func resourceChronicleFeedDelete(d *schema.ResourceData, meta interface{}) error {
	if d.Get("deletion_policy").(string) == "PREVENT" {
		return fmt.Errorf("cannot destroy ChronicleFeed without setting deletion_policy=\"DELETE\" and running `terraform apply`")
	}
	if d.Get("deletion_policy").(string) == "ABANDON" {
		log.Printf("[DEBUG] deletion_policy set to \"ABANDON\", removing Feed %q from Terraform state without deletion", d.Id())
		return nil
	}
	config := meta.(*transport_tpg.Config)
	userAgent, err := tpgresource.GenerateUserAgentString(d, config.UserAgent)
	if err != nil {
		return err
	}

	billingProject := ""

	project, err := tpgresource.GetProject(d, config)
	if err != nil {
		return fmt.Errorf("Error fetching project for Feed: %s", err)
	}
	billingProject = project
	url, err := tpgresource.ReplaceVars(d, config, transport_tpg.BaseUrl(Product, config)+"projects/{{project}}/locations/{{location}}/instances/{{instance}}/feeds/{{feed}}")
	if err != nil {
		return err
	}

	var obj map[string]interface{}

	// err == nil indicates that the billing_project value was found
	if bp, err := tpgresource.GetBillingProject(d, config); err == nil {
		billingProject = bp
	}

	headers := make(http.Header)

	log.Printf("[DEBUG] Deleting Feed %q", d.Id())
	res, err := transport_tpg.SendRequest(transport_tpg.SendRequestOptions{
		Config:    config,
		Method:    "DELETE",
		Project:   billingProject,
		RawURL:    url,
		UserAgent: userAgent,
		Body:      obj,
		Timeout:   d.Timeout(schema.TimeoutDelete),
		Headers:   headers,
	})
	if err != nil {
		return transport_tpg.HandleNotFoundError(err, d, "Feed")
	}

	log.Printf("[DEBUG] Finished deleting Feed %q: %#v", d.Id(), res)
	return nil
}

